-- Create "alert_events" table
CREATE TABLE "alert_events" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "source" character varying NOT NULL,
  "source_fingerprint" character varying NOT NULL,
  "canonical_fingerprint" character varying NOT NULL,
  "labels" jsonb NOT NULL,
  "annotations" jsonb NOT NULL,
  "raw_payload" jsonb NULL,
  "status" character varying NOT NULL DEFAULT 'firing',
  "starts_at" timestamptz NOT NULL,
  "ends_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "alertevent_labels" to table: "alert_events"
CREATE INDEX "alertevent_labels" ON "alert_events" USING GIN ("labels");
-- Create index "alertevent_source_canonical_fingerprint_starts_at" to table: "alert_events"
CREATE UNIQUE INDEX "alertevent_source_canonical_fingerprint_starts_at" ON "alert_events" ("source", "canonical_fingerprint", "starts_at");
-- Create index "alertevent_source_status" to table: "alert_events"
CREATE INDEX "alertevent_source_status" ON "alert_events" ("source", "status");
-- Create "alert_groups" table
CREATE TABLE "alert_groups" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "group_key" character varying NOT NULL,
  "dimensions" jsonb NOT NULL,
  "severity" character varying NOT NULL DEFAULT 'unknown',
  "event_count" bigint NOT NULL DEFAULT 0,
  "status" character varying NOT NULL DEFAULT 'active',
  "first_seen_at" timestamptz NOT NULL,
  "last_seen_at" timestamptz NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "alertgroup_dimensions" to table: "alert_groups"
CREATE INDEX "alertgroup_dimensions" ON "alert_groups" USING GIN ("dimensions");
-- Create index "alertgroup_group_key_first_seen_at" to table: "alert_groups"
CREATE UNIQUE INDEX "alertgroup_group_key_first_seen_at" ON "alert_groups" ("group_key", "first_seen_at");
-- Create index "alertgroup_status_last_seen_at" to table: "alert_groups"
CREATE INDEX "alertgroup_status_last_seen_at" ON "alert_groups" ("status", "last_seen_at");
-- Create "alert_event_groups" table
CREATE TABLE "alert_event_groups" (
  "alert_event_id" bigint NOT NULL,
  "alert_group_id" bigint NOT NULL,
  PRIMARY KEY ("alert_event_id", "alert_group_id"),
  CONSTRAINT "alert_event_groups_alert_event_id" FOREIGN KEY ("alert_event_id") REFERENCES "alert_events" ("id") ON UPDATE NO ACTION ON DELETE CASCADE,
  CONSTRAINT "alert_event_groups_alert_group_id" FOREIGN KEY ("alert_group_id") REFERENCES "alert_groups" ("id") ON UPDATE NO ACTION ON DELETE CASCADE
);
-- Create "evidence_snapshots" table
CREATE TABLE "evidence_snapshots" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "digest" character varying NOT NULL,
  "payload" jsonb NOT NULL,
  "provenance" jsonb NOT NULL,
  "status" character varying NOT NULL DEFAULT 'complete',
  "missing_fields" jsonb NULL,
  "created_by_workflow" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "alert_group_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "evidence_snapshots_alert_groups_snapshots" FOREIGN KEY ("alert_group_id") REFERENCES "alert_groups" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "evidencesnapshot_alert_group_id_created_at" to table: "evidence_snapshots"
CREATE INDEX "evidencesnapshot_alert_group_id_created_at" ON "evidence_snapshots" ("alert_group_id", "created_at");
-- Create index "evidencesnapshot_alert_group_id_digest" to table: "evidence_snapshots"
CREATE UNIQUE INDEX "evidencesnapshot_alert_group_id_digest" ON "evidence_snapshots" ("alert_group_id", "digest");
-- Create "diagnosis_tasks" table
CREATE TABLE "diagnosis_tasks" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "workflow_id" character varying NOT NULL,
  "run_id" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'pending',
  "failure_reason" character varying NULL,
  "started_at" timestamptz NULL,
  "finished_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "evidence_snapshot_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "diagnosis_tasks_evidence_snapshots_tasks" FOREIGN KEY ("evidence_snapshot_id") REFERENCES "evidence_snapshots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "diagnosistask_status_created_at" to table: "diagnosis_tasks"
CREATE INDEX "diagnosistask_status_created_at" ON "diagnosis_tasks" ("status", "created_at");
-- Create index "diagnosistask_workflow_id" to table: "diagnosis_tasks"
CREATE INDEX "diagnosistask_workflow_id" ON "diagnosis_tasks" ("workflow_id");
-- Create index "diagnosistask_workflow_id_run_id" to table: "diagnosis_tasks"
CREATE UNIQUE INDEX "diagnosistask_workflow_id_run_id" ON "diagnosis_tasks" ("workflow_id", "run_id");
-- Create "diagnosis_task_events" table
CREATE TABLE "diagnosis_task_events" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "kind" character varying NOT NULL,
  "payload" jsonb NULL,
  "dedupe_key" character varying NULL,
  "occurred_at" timestamptz NOT NULL,
  "recorded_at" timestamptz NOT NULL,
  "task_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "diagnosis_task_events_diagnosis_tasks_events" FOREIGN KEY ("task_id") REFERENCES "diagnosis_tasks" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "diagnosistaskevent_task_id_dedupe_key" to table: "diagnosis_task_events"
CREATE UNIQUE INDEX "diagnosistaskevent_task_id_dedupe_key" ON "diagnosis_task_events" ("task_id", "dedupe_key");
-- Create index "diagnosistaskevent_task_id_occurred_at" to table: "diagnosis_task_events"
CREATE INDEX "diagnosistaskevent_task_id_occurred_at" ON "diagnosis_task_events" ("task_id", "occurred_at");
